import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  CardContent,
  Grid,
  TextField,
  Button,
  FormControlLabel,
  Switch,
  Typography,
  Select,
  MenuItem,
  FormControl,
  InputLabel,
  Alert,
  Snackbar,
  Stack,
  IconButton,
  Tooltip,
  CircularProgress,
  LinearProgress
} from '@mui/material';
import { getSettings, updateSettings } from '../services/api';
import { Info as InfoIcon } from '@mui/icons-material';

const Settings = () => {
  const [settings, setSettings] = useState({
    network: {
      theme: 'auto',
      password: '',
      confirmPassword: '',
      port: 2345
    },
    dns: {
      mainIP: '10.0.0.1',
      dnsType: 'IPV4',
      usePTConnection: false
    },
    proxy: {
      proxyName: 'Proxy',
      yacdPassword: ''
    }
  });

  const [loading, setLoading] = useState(false);
  const [error, setError] = useState(null);
  const [success, setSuccess] = useState(false);

  useEffect(() => {
    fetchSettings();
  }, []);

  const fetchSettings = async () => {
    try {
      setLoading(true);
      const data = await getSettings();
      setSettings(data);
    } catch (err) {
      setError('Failed to load settings');
    } finally {
      setLoading(false);
    }
  };

  const handleChange = (section, field) => (event) => {
    setSettings(prev => ({
      ...prev,
      [section]: {
        ...prev[section],
        [field]: event.target.type === 'checkbox' ? event.target.checked : event.target.value
      }
    }));
  };

  const handleSubmit = async (section) => {
    try {
      setLoading(true);
      await updateSettings({ [section]: settings[section] });
      setSuccess(true);
    } catch (err) {
      setError('Failed to update settings');
    } finally {
      setLoading(false);
    }
  };

  const handleOpenYacd = () => {
    window.open('/ui/yacd/', '_blank');
  };

  return (
    <Box>
      <Snackbar 
        open={success} 
        autoHideDuration={3000} 
        onClose={() => setSuccess(false)}
      >
        <Alert severity="success">操作成功</Alert>
      </Snackbar>

      <Snackbar 
        open={!!error} 
        autoHideDuration={3000} 
        onClose={() => setError(null)}
      >
        <Alert severity="error">{error}</Alert>
      </Snackbar>

      <Card 
        sx={{ 
          mb: 1.5,
          background: (theme) => 
            theme.palette.mode === 'dark' 
              ? 'linear-gradient(90deg, #1a237e 0%, #311b92 100%)'
              : 'linear-gradient(90deg, #3949ab 0%, #5e35b1 100%)',
          color: '#fff',
          boxShadow: (theme) =>
            theme.palette.mode === 'dark'
              ? '0 2px 4px -1px rgba(0,0,0,0.4)'
              : '0 2px 4px -1px rgba(0,0,0,0.2)',
        }}
      >
        <CardContent sx={{ py: 1.5, px: 2, '&:last-child': { pb: 1.5 } }}>
          <Stack direction="row" alignItems="center" spacing={2}>
            <Typography variant="h5" sx={{ fontWeight: 500, color: 'inherit' }}>
              系统设置
            </Typography>
            {loading && (
              <Box sx={{ display: 'flex', alignItems: 'center' }}>
                <CircularProgress size={20} thickness={4} sx={{ color: 'rgba(255,255,255,0.8)' }} />
              </Box>
            )}
          </Stack>
        </CardContent>
      </Card>

      {loading && <LinearProgress sx={{ mb: 1 }} />}

      <Grid container spacing={1.5}>
        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" sx={{ mb: 2 }}>网络设置</Typography>
              <Stack spacing={2}>
                <TextField
                  fullWidth
                  label="监听地址"
                  value={settings.listenAddr}
                  onChange={(e) => handleChange('listenAddr', e.target.value)}
                  size="small"
                />
                <TextField
                  fullWidth
                  label="监听端口"
                  value={settings.listenPort}
                  onChange={(e) => handleChange('listenPort', e.target.value)}
                  size="small"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableIPv6}
                      onChange={(e) => handleChange('enableIPv6', e.target.checked)}
                      size="small"
                    />
                  }
                  label="启用 IPv6"
                />
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12} md={6}>
          <Card>
            <CardContent>
              <Typography variant="h6" sx={{ mb: 2 }}>DNS 设置</Typography>
              <Stack spacing={2}>
                <TextField
                  fullWidth
                  label="上游 DNS"
                  value={settings.upstreamDNS}
                  onChange={(e) => handleChange('upstreamDNS', e.target.value)}
                  size="small"
                />
                <TextField
                  fullWidth
                  label="DNS 缓存时间"
                  value={settings.cacheTTL}
                  onChange={(e) => handleChange('cacheTTL', e.target.value)}
                  size="small"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableDNSSEC}
                      onChange={(e) => handleChange('enableDNSSEC', e.target.checked)}
                      size="small"
                    />
                  }
                  label="启用 DNSSEC"
                />
              </Stack>
            </CardContent>
          </Card>
        </Grid>

        <Grid item xs={12}>
          <Card>
            <CardContent>
              <Typography variant="h6" sx={{ mb: 2 }}>安全设置</Typography>
              <Stack spacing={2}>
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableLogging}
                      onChange={(e) => handleChange('enableLogging', e.target.checked)}
                      size="small"
                    />
                  }
                  label="启用日志记录"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableMetrics}
                      onChange={(e) => handleChange('enableMetrics', e.target.checked)}
                      size="small"
                    />
                  }
                  label="启用指标收集"
                />
                <FormControlLabel
                  control={
                    <Switch
                      checked={settings.enableCache}
                      onChange={(e) => handleChange('enableCache', e.target.checked)}
                      size="small"
                    />
                  }
                  label="启用缓存"
                />
              </Stack>
            </CardContent>
          </Card>
        </Grid>
      </Grid>

      <Box sx={{ mt: 2, display: 'flex', justifyContent: 'flex-end' }}>
        <Button
          variant="contained"
          onClick={handleSave}
          disabled={loading}
          size="small"
        >
          保存设置
        </Button>
      </Box>
    </Box>
  );
};

export default Settings;
